from flask import Flask, request, jsonify
from pymemcache.client.base import Client
from pymemcache import serde
import time
import sqlite3

app = Flask(__name__)

# Connect to Memcached
client = Client(('localhost', 11211), serializer=serde.python_memcache_serializer, deserializer=serde.python_memcache_deserializer)

# Connect to SQLite database
conn = sqlite3.connect('database.db')
c = conn.cursor()

@app.route('/api/data', methods=['GET'])
def get_data():
    key = 'api_data'
    data = client.get(key)
    if data is None:
        # If data is not in cache, fetch from database
        c.execute("SELECT * FROM data")
        data = c.fetchall()
        # Store data in cache with TTL of 60 seconds
        client.set(key, data, expire=60)
    return jsonify(data)

@app.route('/api/response', methods=['GET'])
def get_response():
    key = 'api_response'
    response = client.get(key)
    if response is None:
        # If response is not in cache, generate response
        response = {"status": "success", "data": "This is a response from the API."}
        # Store response in cache with TTL of 120 seconds
        client.set(key, response, expire=120)
    return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)